import aiohttp
import asyncio
import ipaddress
import socket
from urllib.parse import urlparse
from typing import List, Dict

# Whitelist protokol yang aman
ALLOWED_SCHEMES = {'http', 'https'}

def is_safe_url(url: str) -> bool:
    """
    Validasi URL untuk mencegah SSRF.
    Memblokir akses ke internal IP, localhost, dan protokol non-http.
    """
    try:
        parsed = urlparse(url)

        # Cek protokol
        if parsed.scheme not in ALLOWED_SCHEMES:
            return False

        # Resolve hostname ke IP
        hostname = parsed.hostname
        if not hostname:
            return False

        # Cek apakah hostname adalah IP langsung
        try:
            ip = ipaddress.ip_address(hostname)
        except ValueError:
            # Resolve DNS
            try:
                addresses = socket.getaddrinfo(hostname, None, socket.AF_INET, socket.SOCK_STREAM)
                ips = [ipaddress.ip_address(addr[4][0]) for addr in addresses]
            except socket.gaierror:
                return False
        else:
            ips = [ip]

        # Validasi setiap IP hasil resolve (mencegah DNS Rebinding)
        for ip in ips:
            if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_multicast:
                return False

        return True
    except Exception:
        return False

